\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Channel strip with transformer-style harmonic coloration, Neve-style shelf, Trident-style HPF, plus a VCA compressor, expander and gate.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Shared UI library for citizenkeith plugins. Based on work by Geraint Luff.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Garden Hose Delay - Time Cube Emulator\par}
{\pard \ql \f0 \sa180 \li0 \fi0 An emulation of the Cooper Time Cube, a classic electromechanical delay unit that created its characteristic doubling effect by sending audio through a coiled garden hose as a transmission line.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Frippertronics-inspired tape loop delay. Variable loop length, feedback, damping, saturation, and wow/flutter modulation. Supports tempo sync with seven time divisions.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Good quality tape-style delay with optimized memory layout and ping pong. Based on work by LOSER (JS:Saturation) and Cockos (JS:Delay) with additional code from Sault. Ping pong functionality inspired by Stillwell. Memory layout optimized by Claude AI.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Emulation of the Watkins WEM Project V Fuzz pedal, a sophisticated 8-transistor British fuzz from the late 1960s. Features asymmetric quasi-complementary clipping, inductor resonance modeling, and dynamic octave effects. Famous for use by Brian Eno and Robert Fripp on classic recordings. This JSFX released under GPLv3 license\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Upward compressor inspired by analog FM radio processing. Boosts quiet passages while leaving loud peaks untouched.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 SSL/Sonitus-inspired glue compression for mix bus duty\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 ReaChoir - Harmonized Delay\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Tempo-synced delay with pitch-shifted harmonized echoes.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Port of igorski's Rechoir VST (https://github.com/igorski/rechoir)\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Features:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Tempo-synced delay (quantized to 16th notes)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Pitch shifting (\u177 ?1 octave)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab 7 musical scales for harmonization\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Square wave LFOs (tempo-synced modulation)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Independent stereo modulation (Odd/Even channels)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Freeze mode with reverb\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Lowpass filter with resonance\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Bit reduction/decimator\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Original VST by igorski JSFX port by citizenkeith\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 MIDI pattern generator. Outputs note-on/off events based on probabilistic pattern generation across 12 scales. Supports project tempo sync or internal BPM. Fully MIDI-spec compliant note-off messages.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Tempo-synced stereo tremolo with morphing wave shapes. Square, triangle, and sine waveforms with smooth morphing, tempo sync, and stereo phase offset.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Cloudbusting Reverb\par}
{\pard \ql \f0 \sa180 \li0 \fi0 An algorithmic reverb plugin featuring parallel comb filters, cascaded allpass diffusion, per-comb LFO modulation, high-frequency damping, input filtering, pre-delay, and early reflections.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Credits\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Based on the CloudSeed reverb algorithm by Valdemar Erlingsson (Ghost Note Audio). Original CloudSeed: https://github.com/GhostNoteAudio/CloudSeedCore\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 License\par}
{\pard \ql \f0 \sa180 \li0 \fi0 This plugin is released under the MIT License, matching the CloudSeed source.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 CloudSeed original license: MIT License - Copyright (c) 2017 Valdemar Erlingsson\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Cloudbusting Reverb JSFX port: MIT License - Copyright (c) 2026 citizenkeith\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Permission is hereby granted, free of charge, to any person obtaining a copy of this software and associated documentation files (the "Software"), to deal in the Software without restriction, including without limitation the rights to use, copy, modify, merge, publish, distribute, sublicense, and/or sell copies of the Software, and to permit persons to whom the Software is furnished to do so.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Stereo widener, BBD chorus, ping pong delay and three reverb choices, for a Robin Guthrie-inspired tone.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Emulation of the EMS Synthi AKS modular synthesizer. Oscillator with drift, 4-pole ladder filter, ADSR envelope, ring modulator, Sample & Hold with selectable source routing, and MIDI input with pitch bend. Custom GUI: hand-drawn horizontal sliders in color-coded sections.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
